var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그건 너무 위험합니다, 당주님!","JPN":"それはあまりにも危険です、当主！","ENG":"That is far too dangerous, Lady Nanahara!","TWN":"這太危險了，堂主！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"신기도 없이 결계를 복원하겠다니요!","JPN":"神器なしで結界を復元するなんて！","ENG":"How are you to restore the barrier without it?","TWN":"竟然要在沒有神器的情況下復原結界！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이대로 영지를 내버려두면 현실은 완전히 잠식되고 말겠죠.","JPN":"このまま領地を放っておけば現実は完全に飲み込まれてしまいます。","ENG":"If we leave our lands in this state, reality will be completely corrupted.","TWN":"再繼續坐視不管的話，現世會完全被侵蝕的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금도 이미 많은 사람들이 저승의 역귀들로 인해 고통받고 있습니다.","JPN":"今でもすでに多くの人々が冥府の疫鬼のせいで苦しんでいます。","ENG":"Even now, people are suffering from the Afterlife's Plagued Ghosts.","TWN":"現在有許多人已經因為地獄的疫鬼而受苦，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"결계옥을 언제 다시 되찾을 지 모르는 상황에서, 영지를 방치할 수는 없으니까요.","JPN":"結界玉をいつ取り戻せるかわからない状況で、領地を放置するわけにはいきません。","ENG":"We do not know when or if we will ever get Akaitama back. However, I cannot just abandon our lands.","TWN":"也不知道何時才能找回結界玉石，必須想辦法對領地做些什麼。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"봉인역의 결계는 명부신의 영혼으로 유지해오던 것입니다.","JPN":"封印域の結界は冥府の神の魂で維持してきました。","ENG":"The Seal Domain's barrier has been maintained by the Nether God's soul.","TWN":"封印域的結界是靠著冥府神的靈魂而維持的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제아무리 당주님이라고 해도 사람의 영혼으로는 버티지 못할 겁니다!","JPN":"いくら当主であっても人の魂では耐えられないはずです！","ENG":"Even if it is you, a mortal soul cannot withstand it!","TWN":"堂主也是人，人的靈魂是無法支撐的！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"더 이상 희생을 치르지 않겠다고 하신 말씀을…… 잊으신 겁니까?","JPN":"もうこれ以上の犠牲は払わないというお言葉……お忘れですか？","ENG":"Or did you forget... that you would not commit to any more sacrifices...?","TWN":"您忘記……您說過不會再造成犧牲嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유…….","JPN":"千冬……","ENG":"Chifuyu...","TWN":"千冬……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"걱정 마세요. 저도 제가 신의 영혼을 대신할 수 없다는 것쯤은 알고 있습니다.","JPN":"心配しないでください。私も自分が神の魂の代わりにはなれないということくらいは知っています。","ENG":"Worry not. I know as well that I am not capable of replacing a god's soul.","TWN":"你放心，我自己也很清楚我無法取代神的靈魂。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님. 제 말은 그런 뜻이 아니라……","JPN":"当主。私の話はそういう意味では……","ENG":"Lady Nanahara... You know that is not what I meant...","TWN":"堂主，我不是那個意思……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"신기를 되찾을 때까지.","JPN":"神器を取り戻すまで。","ENG":"Just until we retrieve the Sacred Treasure.","TWN":"撐到把神器找回來就好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그때까지만이라도 결계가 버텨줄 수 있다면 그걸로 충분해요.","JPN":"その時までだけでも結界が耐えてくれるのならそれで十分です。","ENG":"If the barrier can withhold until then, it will be more than enough.","TWN":"結界只要能夠撐到那時候就好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니, 제가 봉인역에서 의식을 치르는 동안 호위를 부탁할게요.","JPN":"ですので、私が封印域で儀式を行っている間に護衛をよろしくお願いします。","ENG":"So please... Protect my side while I perform the ritual at the Seal Domain.","TWN":"我在封印域舉行儀式時，就麻煩千冬護衛我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"As you wish.","TWN":"好吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 연달아 일어난 전투로 연합원들의 피해와 피로가 너무 큽니다.","JPN":"ですが、立て続けの戦闘で連合員の被害と疲労は甚大です。","ENG":"However, the ongoing battles has withered away our forces.","TWN":"只是接二連三的出戰，給聯盟成員帶來不小的傷害和疲勞。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이런 상황에서 저희만으로 영지의 역귀들을 막아낼 수 있을지 걱정이군요.","JPN":"このような状況下で私たちだけで領地の疫鬼を止められるのでしょうか。","ENG":"I am concerned that we might not be enough to protect our lands from the Plagued Ghost.","TWN":"在這種情況下，我擔心光憑我們幾個有辦法抵擋領地的疫鬼嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희뿐만이 아닙니다.","JPN":"私たちだけではありません。","ENG":"It will not just be us.","TWN":"不會只有我們幾個。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라 연합의 가문들은 평시에는 떨어져 지내고 있지만……","JPN":"七原連合の家門は普段は離れて暮らしていますが……","ENG":"The families of the Nahahara Alliance may live far apart...","TWN":"七原聯盟的家族雖然平時都散居各地……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……어려운 때에는 모두가 함께하기로 맹세했으니까요.","JPN":"……困った時にはみなで力を合わせることを誓いましたから。","ENG":"...But they have vowed to gather in hardship.","TWN":"……但大家是發過誓的，只要聯盟有危險大家就會一呼百應。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_MONKEY","text":{"KOREA":"요루 가문의 당주, 요루 사토시. 간만에 나나하라 당주님께 인사 올립니다.","JPN":"夜家当主、夜悟。お久しぶりに七原家ご当主にご挨拶申し上げます。","ENG":"Yoru Satoshi, head of the Yoru family. Long time no see, Lady Nanahara.","TWN":"夜家族的堂主，夜里志向七原堂主請安。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_OWL","text":{"KOREA":"아카마 가문의 당주, 아카마 히스이. 형제들과 함께 나나하라 당주님을 뵙습니다.","JPN":"赤間家当主、赤間翡翠。兄弟とともに七原家ご当主にお目にかかります。","ENG":"Akama Hisui, head of the Akama family. My brothers and I share our greeting to you, Lady Nanahara.","TWN":"赤間家族的堂主，赤間翡翠與眾兄弟見過七原堂主。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"모두들, 혼란한 때에 어려움을 무릅쓰고 이 자리에 모여 주셔서 고맙습니다.","JPN":"皆さま、混乱している中、難しい状況にもかかわらずこの場にお集まりいただきありがとうございます。","ENG":"Thank you, everyone, for coming here in the perilous of times.","TWN":"首先要謝謝各位，在如此動盪之時不畏困難齊聚於此。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금도 많은 이들이 자신의 터전과 가족을 지키기 위해 목숨을 걸고 있어요.","JPN":"今も多くの者たちが自分の住処と家族を守るために命をかけています。","ENG":"As we speak, many are risking their lives to protect their lands and beloved.","TWN":"現在也有許多人正在拼命守護自己的家園，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"혼탁한 무리들이 나타나 현실을 위협하고, 지금은 영지의 결계마저 무너져버린 상황.","JPN":"邪な者たちが現れ現実を脅かし、領地の結界さえ崩れてしまった状況です。","ENG":"Chaos creeps, threatening our reality. And now, the lands' barrier has even fallen.","TWN":"但有一群人出現危害現世，連領地的結界都已經瓦解。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 나나하라의 무녀로서, 무너진 결계를 복원하기 위해 여러분의 힘을 빌리고자 합니다.","JPN":"私は七原家の巫女として、崩れた結界を復元するために皆さまの力をお借りしたいと思います。","ENG":"I, as the priestess of Nanahara, ask of you to lend me your strength in recovering the fallen barrier.","TWN":"我身為七原的巫女，需要借助各位的力量來復原結界。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_MONKEY","text":{"KOREA":"저승의 출입문을 다시 틀어막는 작업이니, 사령들이 넘어오려고 발버둥을 치겠군요.","JPN":"冥府の出入口を再び封ずる作業ですから、邪霊たちがこちらへ来ようと足掻くでしょうね。","ENG":"As it closes the gates of the Afterlife, ghouls will try to stop us.","TWN":"畢竟任務是要堵住地獄的門，那些邪靈勢必會拚死要越過來吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_OWL","text":{"KOREA":"걱정 마십쇼. 사령이라곤 하지만 결국 실체를 가진 괴물일 뿐. 저희가 반드시 막아내겠슴다.","JPN":"心配しなさんな。邪霊とはいえ、所詮は実体を持つ化け物。俺たちが必ず止めて見せるっす。","ENG":"Worry not. They are mere monsters trapped within their bodies. We will stop them no matter what.","TWN":"請放心，說是邪靈，但實際上只是有形體的怪物，我們絕對會擋下它們的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"연합원들은 준비를 모두 마쳤습니다.","JPN":"連合員は全員準備を終えました。","ENG":"All members have already made their preparation.","TWN":"既然聯盟成員都已預備妥當，"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그럼, 복원 의식을 위해 봉인역으로 이동하도록 하시죠.","JPN":"それでは、復元儀式のために封印域に移動しましょう。","ENG":"Then, let us move to the Seal Domain, where the ritual will be held.","TWN":"那就前往封印域預備進行復原儀式吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};